/**
 * Global Strategy Economy — Browse, discover, and follow strategies.
 * RESEARCH DISCOVERY ONLY — no execution.
 */
import { useState, useEffect, useCallback, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { api, apiPost } from '../utils/api';
import GlassPanel from '../components/ui/GlassPanel';
import StatCard from '../components/ui/StatCard';
import usePageTitle from '../hooks/usePageTitle';
import s from './EconomyPage.module.css';

const BADGE_COLORS = { high_alpha: '#22C55E', trusted: '#BC8CFF', regime_stable: '#60A5FA', popular: '#D29922', walk_forward_validated: '#22C55E' };

function Badge({ name }) {
  const c = BADGE_COLORS[name] || '#90A3AF';
  return (
    <span className={s.badge} style={{ background: c + '22', color: c }}>
      {name.replace(/_/g, ' ').toUpperCase()}
    </span>
  );
}

function StrategyCard({ s: strat, onClick }) {
  return (
    <GlassPanel hover onClick={onClick} style={{ cursor: 'pointer' }}>
      <div className={s.cardHeader}>
        <div>
          <div className={s.cardTitle}>{strat.title || strat.strategy_root_id}</div>
          <div className={s.cardSubtitle}>{strat.family} · {strat.direction}</div>
        </div>
        <div className={s.cardAlpha} style={{ color: strat.alpha_score >= 0.7 ? '#22C55E' : '#E5E7DB' }}>
          {(strat.alpha_score || 0).toFixed(2)}
        </div>
      </div>
      <div className={s.metricsGrid}>
        {[
          { l: 'Sharpe', v: (strat.sharpe || 0).toFixed(2) },
          { l: 'PF', v: (strat.profit_factor || 0).toFixed(2) },
          { l: 'Rep', v: (strat.reputation_score || 0).toFixed(2) },
          { l: 'DD', v: `${((strat.max_drawdown || 0) * 100).toFixed(0)}%` },
        ].map(m => (
          <div key={m.l} className={s.metricCell}>
            <div className={s.metricValue}>{m.v}</div>
            <div className={s.metricLabel}>{m.l}</div>
          </div>
        ))}
      </div>
      {strat.badges?.length > 0 && <div className={s.badgeRow}>{strat.badges.slice(0, 3).map(b => <Badge key={b} name={b} />)}</div>}
      <div className={s.cardFooter}>
        <span>{strat.followers || strat.follower_count || 0} followers</span>
        <span>{strat.risk_level || 'medium'} risk</span>
        {strat.publish_state === 'featured' && <span className={s.featured}>FEATURED</span>}
      </div>
    </GlassPanel>
  );
}

export default function EconomyPage() {
  usePageTitle('Strategy Economy');
  const nav = useNavigate();
  const [strategies, setStrategies] = useState([]);
  const [trending, setTrending] = useState([]);
  const [creators, setCreators] = useState([]);
  const [stats, setStats] = useState(null);
  const [lbView, setLbView] = useState('overall');
  const [leaderboard, setLeaderboard] = useState([]);
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(true);

  const fetchAll = useCallback(async () => {
    const [st, t, c, ss, lb] = await Promise.all([
      api('/api/economy/strategies?limit=30'),
      api('/api/economy/trending'),
      api('/api/economy/creators/top'),
      api('/api/economy/stats'),
      api(`/api/economy/leaderboards?view=${lbView}&limit=20`),
    ]);
    if (st) setStrategies(st.strategies || []);
    if (t) setTrending(t.trending || []);
    if (c) setCreators(c.creators || []);
    if (ss) setStats(ss);
    if (lb) setLeaderboard(lb.strategies || []);
    setLoading(false);
  }, [lbView]);

  useEffect(() => { fetchAll(); }, [fetchAll]);

  const filtered = useMemo(() => {
    if (!search) return strategies;
    const q = search.toLowerCase();
    return strategies.filter(st => (st.title || '').toLowerCase().includes(q) || (st.family || '').toLowerCase().includes(q));
  }, [strategies, search]);

  if (loading) return <div className={s.loading}>Loading economy...</div>;

  const eco = stats?.economy || {};

  return (
    <div className={s.page}>
      <div className={s.headerBlock}>
        <h1 className={s.title}>Global Strategy Economy</h1>
        <p className={s.subtitle}>Research discovery — browse, follow, track</p>
      </div>

      {/* Stats */}
      <div className={s.statsGrid}>
        <StatCard label="Published" value={eco.total || 0} accentColor="#60A5FA" compact />
        <StatCard label="Featured" value={eco.by_state?.featured || 0} accentColor="#D29922" compact />
        <StatCard label="Total Followers" value={stats?.engagement?.total_followers || 0} accentColor="#22C55E" compact />
        <StatCard label="Trending" value={trending.length} accentColor="#BC8CFF" compact />
        <StatCard label="Creators" value={creators.length} accentColor="#60A5FA" compact />
      </div>

      {/* Trending */}
      {trending.length > 0 && (
        <GlassPanel className={s.trendingPanel}>
          <h3 className={s.trendingTitle}>TRENDING NOW</h3>
          <div className={s.trendingScroll}>
            {trending.slice(0, 8).map(t => (
              <div key={t.strategy_id} onClick={() => nav(`/economy/strategy/${t.strategy_id}`)} className={s.trendingCard}>
                <div className={s.trendingCardTitle}>{t.title || t.strategy_id}</div>
                <div className={s.trendingCardMeta}>{t.family} · {t.followers} followers</div>
                <div className={s.trendingCardScore}>
                  {t.alpha_score?.toFixed(3)}
                </div>
              </div>
            ))}
          </div>
        </GlassPanel>
      )}

      {/* Leaderboard + Creators */}
      <div className={s.mainGrid}>
        <GlassPanel>
          <div className={s.lbHeader}>
            <h3 className={s.sectionTitle}>LEADERBOARD</h3>
            <select value={lbView} onChange={e => setLbView(e.target.value)} className={s.select}>
              {['overall','new','stable','reputation','trending','cross_asset','featured','evolved'].map(v => (
                <option key={v} value={v}>{v.replace('_', ' ')}</option>
              ))}
            </select>
          </div>
          <table className={s.table}>
            <thead><tr className={s.theadRow}>
              {['#', 'Strategy', 'Alpha', 'Rep', 'Sharpe', 'Followers'].map(h => (
                <th key={h} className={s.th}>{h}</th>
              ))}
            </tr></thead>
            <tbody>
              {leaderboard.map(lb => (
                <tr key={lb.strategy_root_id || lb.rank} className={s.tr}>
                  <td className={s.td} style={{ color: lb.rank <= 3 ? '#D29922' : '#90A3AF', fontWeight: lb.rank <= 3 ? 700 : 400 }}>{lb.rank}</td>
                  <td className={s.tdName}>{lb.title}</td>
                  <td className={s.td} style={{ color: lb.alpha_score >= 0.7 ? '#22C55E' : '#E5E7DB' }}>{(lb.alpha_score || 0).toFixed(3)}</td>
                  <td className={s.td}>{(lb.reputation_score || 0).toFixed(2)}</td>
                  <td className={s.td}>{(lb.sharpe || 0).toFixed(2)}</td>
                  <td className={s.tdSec}>{lb.followers || 0}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </GlassPanel>

        <GlassPanel>
          <h3 className={s.sectionTitleMb}>TOP ORIGINS</h3>
          {creators.map(c => (
            <div key={c.creator_id} onClick={() => nav(`/economy/creator/${c.creator_id}`)} className={s.creatorRow}>
              <div className={s.creatorName}>{c.display_name}</div>
              <div className={s.creatorMeta}>
                {c.published_count} published · avg rep {(c.avg_reputation || 0).toFixed(2)}
              </div>
            </div>
          ))}
        </GlassPanel>
      </div>

      {/* Strategy Grid */}
      <GlassPanel className={s.searchPanel}>
        <input type="text" placeholder="Search strategies..." value={search} onChange={e => setSearch(e.target.value)} className={s.searchInput} />
      </GlassPanel>

      <div className={s.cardGrid}>
        {filtered.map(st => (
          <StrategyCard key={st.strategy_version_id || st.strategy_root_id} s={st}
            onClick={() => nav(`/economy/strategy/${st.strategy_version_id || st.strategy_root_id}`)} />
        ))}
      </div>

      {filtered.length === 0 && (
        <GlassPanel className={s.emptyBlock}>
          <div className={s.emptyText}>No strategies published yet. Sync from catalog first.</div>
        </GlassPanel>
      )}
    </div>
  );
}
